module RefModule(
    input [7:0] packet,
    input [7:0] filter,
    output reg pass,
    output reg fail
);
  wire [7:0] _tap_packet = packet & {8{1'b1}};

    always @(*) begin
        if (packet == filter) begin
            pass = 1'b1;
            fail = 1'b0;
        end else begin
            pass = 1'b0;
            fail = 1'b1;
        end
    end
endmodule
